import React from 'react';
import { Card, Container } from 'react-bootstrap';

const Research = () => {
  return (
      <>
        <Container className='p-3'>
          <h1>Research Interests</h1>
          <Card className='my-4'>
            <Card.Header>Quantum Computing</Card.Header>
            <Card.Body>
              <Card.Title>Quantum Computing Research</Card.Title>
              <Card.Text>
                I am interested in a variety of research topics, including topic 1, topic 2, and topic 3. 
              </Card.Text>
            </Card.Body>
          </Card>

          <Card>
            <Card.Header>Machine Learning</Card.Header>
            <Card.Body>
              <Card.Title>Machine Learning Research</Card.Title>
              <Card.Text>
                I am interested in a variety of research topics, including topic 1, topic 2, and topic 3. 
              </Card.Text>
            </Card.Body>
          </Card>
        </Container>
      </>

  );
};

export default Research;
